const ESTIMATE_EXACT_ROW_HEAD_WIDTH = 46;
const ESTIMATE_EXACT_COL_HEAD_HEIGHT = 24;

function estimateExactGetSpec(type) {
  return ESTIMATE_EXACT_SPECS[type] || ESTIMATE_EXACT_SPECS[estimateSheetActiveType] || ESTIMATE_EXACT_SPECS["개산견적"];
}

cloneEstimateSheetRows = function(type) {
  const spec = estimateExactGetSpec(type);
  return JSON.parse(JSON.stringify(spec.cells || []));
};

function estimateExactCellKey(r, c) { return (r + 1) + "," + (c + 1); }
function estimateExactCellRef(row, col) { return estimateSheetColumnLabel(col - 1) + row; }
function estimateExactParseNumber(value) {
  if (value === null || value === undefined || value === "") return 0;
  if (typeof value === "number") return value;
  const cleaned = String(value).replace(/[,₩원\s]/g, "");
  const n = Number(cleaned);
  return Number.isFinite(n) ? n : 0;
}
function estimateExactGetValue(rows, ref) {
  const match = String(ref || "").match(/^([A-Z]+)(\d+)$/);
  if (!match) return 0;
  const col = match[1].split("").reduce((sum, ch) => sum * 26 + ch.charCodeAt(0) - 64, 0);
  const row = Number(match[2]);
  return estimateExactParseNumber(rows?.[row - 1]?.[col - 1]);
}
function estimateExactRangeSum(rows, startRef, endRef) {
  const parse = (ref) => {
    const m = ref.match(/^([A-Z]+)(\d+)$/);
    return { col: m[1].split("").reduce((sum, ch) => sum * 26 + ch.charCodeAt(0) - 64, 0), row: Number(m[2]) };
  };
  const a = parse(startRef), b = parse(endRef);
  let sum = 0;
  for (let r = Math.min(a.row, b.row); r <= Math.max(a.row, b.row); r++) {
    for (let c = Math.min(a.col, b.col); c <= Math.max(a.col, b.col); c++) {
      sum += estimateExactParseNumber(rows?.[r - 1]?.[c - 1]);
    }
  }
  return sum;
}
function estimateExactKoreanAmount(num) {
  const n = Math.round(estimateExactParseNumber(num));
  if (!n) return "영";
  // 실무 화면용 간이 변환: 원본 엑셀 NUMBERSTRING 결과와 유사하게 표시
  return n.toLocaleString("ko-KR");
}
function estimateExactMoney(num) { return "₩" + Math.round(estimateExactParseNumber(num)).toLocaleString("ko-KR"); }
function estimateExactEvalFormula(formula, rows) {
  if (!formula) return "";
  const f = String(formula).trim();
  if (f.includes("NUMBERSTRING") || f.includes("DOLLAR")) {
    const target = (f.match(/NUMBERSTRING\(([A-Z]+\d+)/) || [])[1] || (f.match(/DOLLAR\(([A-Z]+\d+)/) || [])[1] || "F20";
    const amount = estimateExactGetValue(rows, target);
    return "일금" + estimateExactKoreanAmount(amount) + "원정 (" + estimateExactMoney(amount) + ")";
  }
  let expr = f.replace(/^=/, "");
  expr = expr.replace(/SUM\(([A-Z]+\d+):([A-Z]+\d+)\)/gi, (_, a, b) => String(estimateExactRangeSum(rows, a, b)));
  expr = expr.replace(/([A-Z]+\d+)/g, (m) => String(estimateExactGetValue(rows, m)));
  if (!/^[0-9+\-*/().\s]+$/.test(expr)) return rows;
  try {
    const result = Function("return (" + expr + ")")();
    return Number.isFinite(result) ? Math.round(result * 100) / 100 : 0;
  } catch (e) {
    return 0;
  }
}
function estimateExactRecalculateRows(type, rows) {
  const spec = estimateExactGetSpec(type);
  Object.entries(spec.formulas || {}).forEach(([key, formula]) => {
    const [r, c] = key.split(",").map(Number);
    if (!rows[r - 1]) rows[r - 1] = [];
    rows[r - 1][c - 1] = estimateExactEvalFormula(formula, rows);
  });
}
function estimateExactFormatValue(value) {
  if (value === null || value === undefined) return "";
  if (typeof value === "number") return Number.isInteger(value) ? String(value) : String(Math.round(value * 100) / 100);
  return String(value);
}
function estimateExactStyleString(style) {
  if (!style) return "";
  return Object.entries(style).map(([k, v]) => `${k}:${v}`).join(";");
}
function estimateExactCellMergeMap(spec) {
  const skip = new Set();
  const start = {};
  (spec.merges || []).forEach(([r1, c1, r2, c2]) => {
    start[`${r1 - 1},${c1 - 1}`] = { rowspan: r2 - r1 + 1, colspan: c2 - c1 + 1 };
    for (let r = r1 - 1; r <= r2 - 1; r++) {
      for (let c = c1 - 1; c <= c2 - 1; c++) {
        if (r !== r1 - 1 || c !== c1 - 1) skip.add(`${r},${c}`);
      }
    }
  });
  return { skip, start };
}
function estimateExactImageStyle(img, spec) {
  const colLeft = (img.from.col || 0);
  const rowTop = (img.from.row || 0);
  const left = ESTIMATE_EXACT_ROW_HEAD_WIDTH + spec.cols.slice(0, colLeft).reduce((a, b) => a + b, 0) + (img.from.colOff || 0) / 9525;
  const top = ESTIMATE_EXACT_COL_HEAD_HEIGHT + spec.rows.slice(0, rowTop).reduce((a, b) => a + b, 0) + (img.from.rowOff || 0) / 9525;
  let width = 70, height = 48;
  if (img.to) {
    const right = ESTIMATE_EXACT_ROW_HEAD_WIDTH + spec.cols.slice(0, img.to.col || 0).reduce((a, b) => a + b, 0) + (img.to.colOff || 0) / 9525;
    const bottom = ESTIMATE_EXACT_COL_HEAD_HEIGHT + spec.rows.slice(0, img.to.row || 0).reduce((a, b) => a + b, 0) + (img.to.rowOff || 0) / 9525;
    width = Math.max(20, right - left);
    height = Math.max(20, bottom - top);
  }
  return `left:${left}px;top:${top}px;width:${width}px;height:${height}px;`;
}

renderEstimateSheetGrid = function() {
  const grid = document.getElementById("estimateSheetGrid");
  if (!grid || !estimateSheetEditorRows) return;
  const spec = estimateExactGetSpec(estimateSheetActiveType);
  const rows = estimateSheetEditorRows;
  estimateExactRecalculateRows(estimateSheetActiveType, rows);
  const merge = estimateExactCellMergeMap(spec);
  const colHeaders = Array.from({ length: spec.maxC }, (_, i) => `<th style="width:${spec.cols[i] || 80}px;min-width:${spec.cols[i] || 80}px">${estimateSheetColumnLabel(i)}</th>`).join("");
  const colgroup = `<col style="width:${ESTIMATE_EXACT_ROW_HEAD_WIDTH}px;min-width:${ESTIMATE_EXACT_ROW_HEAD_WIDTH}px">` + spec.cols.map(w => `<col style="width:${w}px;min-width:${w}px">`).join("");
  const bodyRows = Array.from({ length: spec.maxR }, (_, r) => {
    const cells = Array.from({ length: spec.maxC }, (_, c) => {
      if (merge.skip.has(`${r},${c}`)) return "";
      const mergeInfo = merge.start[`${r},${c}`] || {};
      const value = estimateExactFormatValue(rows?.[r]?.[c]);
      const formula = spec.formulas?.[estimateExactCellKey(r, c)];
      const styleId = spec.styleIds?.[r]?.[c];
      const baseStyle = estimateExactStyleString(spec.styles?.[styleId]);
      const rowHeight = spec.rows[r] || 20;
      const extraStyle = [];
      extraStyle.push(`height:${rowHeight}px`);
      if (estimateSheetActiveType !== "공사비검증" && c >= 7) extraStyle.push("background:#a6a6a6");
      if (r === 1 && c === 0) extraStyle.push("font-size:22pt;font-weight:900;letter-spacing:6px;text-align:center");
      const editable = formula ? "false" : "true";
      const formulaAttr = formula ? ` data-formula="${estimateSheetHtml(formula)}"` : "";
      const spanAttr = `${mergeInfo.rowspan ? ` rowspan="${mergeInfo.rowspan}"` : ""}${mergeInfo.colspan ? ` colspan="${mergeInfo.colspan}"` : ""}`;
      return `<td${spanAttr} class="estimate-exact-cell ${formula ? "estimate-exact-formula" : ""}" data-row="${r}" data-col="${c}"${formulaAttr} contenteditable="${editable}" oninput="updateEstimateSheetCell(this)" style="${baseStyle};${extraStyle.join(";")}">${estimateSheetHtml(value)}</td>`;
    }).join("");
    return `<tr><th class="estimate-sheet-row-head" style="height:${spec.rows[r] || 20}px">${r + 1}</th>${cells}</tr>`;
  }).join("");
  const imgs = (spec.images || []).map(img => `<img class="estimate-exact-image" src="data:${img.mime};base64,${img.data}" style="${estimateExactImageStyle(img, spec)}" alt="">`).join("");
  grid.classList.add("estimate-exact-grid");
  grid.innerHTML = `<div class="estimate-exact-canvas">${imgs}<table class="estimate-exact-table"><colgroup>${colgroup}</colgroup><thead><tr><th class="estimate-sheet-corner"></th>${colHeaders}</tr></thead><tbody>${bodyRows}</tbody></table></div>`;
};

updateEstimateSheetCell = function(cell) {
  if (!estimateSheetEditorRows || cell.dataset.formula) return;
  const r = Number(cell.dataset.row);
  const c = Number(cell.dataset.col);
  if (!estimateSheetEditorRows[r]) estimateSheetEditorRows[r] = [];
  const raw = cell.innerText.replace(/\n/g, " ").trim();
  const numeric = raw !== "" && /^-?[0-9,]+(\.[0-9]+)?$/.test(raw) ? Number(raw.replace(/,/g, "")) : raw;
  estimateSheetEditorRows[r][c] = numeric;
  const wrap = cell.closest(".estimate-sheet-grid-wrap");
  const sx = wrap ? wrap.scrollLeft : 0;
  const sy = wrap ? wrap.scrollTop : 0;
  renderEstimateSheetGrid();
  if (wrap) { wrap.scrollLeft = sx; wrap.scrollTop = sy; }
};

exportEstimateSheetCurrentHtml = function() {
  if (!estimateSheetEditorRows) {
    const first = estimateSheetRecords.find(record => record.type === estimateSheetActiveType);
    estimateSheetEditorRows = first ? JSON.parse(JSON.stringify(first.rows || cloneEstimateSheetRows(estimateSheetActiveType))) : cloneEstimateSheetRows(estimateSheetActiveType);
  }
  renderEstimateSheetGrid();
  const canvas = document.querySelector("#estimateSheetGrid .estimate-exact-canvas");
  const html = `<!doctype html><html><head><meta charset="utf-8"><style>
    body{font-family:Arial,'맑은 고딕',sans-serif;margin:0;background:#fff;}
    .estimate-exact-canvas{position:relative;display:inline-block;background:#fff;}
    .estimate-exact-image{position:absolute;object-fit:contain;z-index:4;pointer-events:none;}
    table{border-collapse:collapse;table-layout:fixed;}
    th,td{border:1px solid #d8e2ef;white-space:pre-wrap;word-break:keep-all;vertical-align:middle;font-size:10pt;padding:2px 5px;}
    th{background:#f1f5f9;font-weight:900;text-align:center;}
  </style></head><body>${canvas ? canvas.outerHTML : ""}</body></html>`;
  const blob = new Blob([html], { type: "application/vnd.ms-excel;charset=utf-8" });
  const a = document.createElement("a");
  a.href = URL.createObjectURL(blob);
  a.download = `CONCOST_${estimateSheetActiveType}_${new Date().toISOString().slice(0,10).replace(/-/g,"")}.xls`;
  document.body.appendChild(a);
  a.click();
  URL.revokeObjectURL(a.href);
  a.remove();
};

if (document.getElementById("estimateSheetManage")) {
  try { renderEstimateSheetManage(); } catch (e) { console.warn("estimate exact render init", e); }
}
